module pipeline_2stage (
    input clk,
    input [4:0] data_in,
    output reg [5:0] data_out
);
    reg [4:0] incremented_value;

    always @(posedge clk) begin
        // Stage 1: Increment by 1
        incremented_value <= data_in + 1;
    end

    always @(posedge clk) begin
        // Stage 2: Multiply by 2
        data_out <= incremented_value * 2;
    end
endmodule
